module register_8bit_enable(obf_clk, enable, d, q);  

    input  obf_clk;  
    input  enable;  
    input  [7:0] d;  
    output  [7:0] q;  
    reg   [7:0]  q; 
    initial q = 0;

    always @(posedge obf_clk)
          begin
            if (enable)
                q <= d;
          end  

endmodule
